"use client";

import { useEffect, useState } from "react";
import { animate, useMotionValue, useTransform, motion } from "framer-motion";

interface AnimatedCounterProps {
  value: number;
  duration?: number;
  prefix?: string;
  suffix?: string;
}

export const AnimatedCounter = ({ value, duration = 2, prefix = "", suffix = "" }: AnimatedCounterProps) => {
  const count = useMotionValue(0);
  const rounded = useTransform(count, (latest) => {
    return Math.floor(latest).toLocaleString();
  });

  useEffect(() => {
    const controls = animate(count, value, { duration: duration, ease: "easeOut" });
    return controls.stop;
  }, [value, duration, count]);

  return (
    <motion.span className="font-bold">
      {prefix}
      <motion.span>{rounded}</motion.span>
      {suffix}
    </motion.span>
  );
};

/**
 * Central API client.
 * Base URL is read from NEXT_PUBLIC_API_URL env var so it works
 * in both local dev (http://localhost:5000) and production.
 */

const BASE_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:5000";

function getToken(): string | null {
  if (typeof window === "undefined") return null;
  return localStorage.getItem("token");
}

interface RequestOptions extends RequestInit {
  auth?: boolean; // attach JWT if true (default: true for non-GET)
}

async function request<T>(
  path: string,
  options: RequestOptions = {}
): Promise<T> {
  const { auth = true, headers = {}, ...rest } = options;

  const token = getToken();
  const authHeader: Record<string, string> =
    auth && token ? { Authorization: `Bearer ${token}` } : {};

  const res = await fetch(`${BASE_URL}${path}`, {
    headers: {
      "Content-Type": "application/json",
      ...authHeader,
      ...(headers as Record<string, string>),
    },
    ...rest,
  });

  const data = await res.json();

  if (!res.ok) {
    throw new Error(data.message || `Request failed: ${res.status}`);
  }

  return data;
}

